module u_module (
    input [2:0] k,
    output reg not_r
);

    always @(*) begin
        case (k)
            3'b000: not_r = 1;
            3'b001: not_r = 0;
            3'b010: not_r = 1;
            3'b011: not_r = 0;
            3'b100: not_r = 1;
            3'b101: not_r = 0;
            3'b110: not_r = 1;
            3'b111: not_r = 0;
            default: not_r = 0; // Default case
        endcase
    end
endmodule
